#include <bits/stdc++.h>
using namespace std;
int k,x,num,n,m,a[30005],b[30005],t[20005],w,sum;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>num;
	memset(a,127/3,sizeof(a));
	memset(b,127/3,sizeof(b));
	for(int i=1; i<=num; i++) {
		cin>>x;
		t[x]++;
	}
	for (int i=1; i<=20000; i++) {
		while (t[i]) {
			t[i]--;
			n++;
			a[n]=i;
		}
	}
	int i=1,j=1;
	k=1;
	while (k<num) {
		if (a[i]<b[j]) {
			w=a[i];
			i++;
		} else {
			w=b[j];
			j++;
		}
		if (a[i]<b[j]) {
			w+=a[i];
			i++;
		} else {
			w+=b[j];
			j++;
		}
		m++;
		b[m]=w;
		k++;
		sum+=w;
	}
	cout<<sum;
	return 0;
}
